    CAMLlocal1(v_result);
    int32_t buf[8];
    memset(buf, 0, sizeof(buf));
    buf[0] = -1;  /* wall_num = -1 (no wall) by default */
    buf[1] = -1;  /* wall_type */
    if (g_fetch_wall_data)
        g_fetch_wall_data(Int_val(v_segnum), Int_val(v_sidenum), buf);
    v_result = caml_alloc(8, 0);
    for (int i = 0; i < 8; i++)
        Store_field(v_result, i, Val_long(buf[i]));
    CAMLreturn(v_result);
}

