void wall_init()
{
	int i;

	Num_walls = 0;
	for (i = 0; i < MAX_WALLS; i++) {
		Walls[i].segnum = Walls[i].sidenum = -1;
		Walls[i].type = WALL_NORMAL;
		Walls[i].flags = 0;
		Walls[i].hps = 0;
		Walls[i].trigger = -1;
		Walls[i].clip_num = -1;
		Walls[i].linked_wall = -1;
	}
	Num_open_doors = 0;
	Num_cloaking_walls = 0;

}

