			stuck_reg = 1;
			cd_ox_register_stuck_objects_effects(
				/* fetch_stuck_objects_data: [num_stuck, (wallnum, objnum, obj_type, obj_id) x 32] */
				[](int32_t* out, int* out_len) {
					out[0] = Num_stuck_objects;
					for (int i = 0; i < MAX_STUCK_OBJECTS; i++) {
						int base = 1 + i * 4;
						out[base + 0] = Stuck_objects[i].wallnum;
						out[base + 1] = Stuck_objects[i].objnum;
						if (Stuck_objects[i].wallnum != -1) {
							out[base + 2] = Objects[Stuck_objects[i].objnum].type;
							out[base + 3] = Objects[Stuck_objects[i].objnum].id;
						} else {
							out[base + 2] = 0;
							out[base + 3] = 0;
						}
					}
				},
				/* write_clear_stuck_objects: packed = [n_flares, objnum_0..n-1, new_num_stuck] */
				[](const int32_t* packed, int len) {
					if (len < 2) return;
					int n_flares = packed[0];
					for (int j = 0; j < n_flares; j++)
						Objects[packed[j + 1]].lifeleft = F1_0 / 8;
					for (int i = 0; i < MAX_STUCK_OBJECTS; i++)
						Stuck_objects[i].wallnum = -1;
					Num_stuck_objects = packed[len - 1];
				});
		}
		cd_ox_clear_stuck_objects();
		return;
	}
#endif
	int	i;

	for (i = 0; i < MAX_STUCK_OBJECTS; i++) {
		if (Stuck_objects[i].wallnum != -1) {
			int	objnum;

			objnum = Stuck_objects[i].objnum;

			if ((Objects[objnum].type == OBJ_WEAPON) && (Objects[objnum].id == FLARE_ID))
				Objects[objnum].lifeleft = F1_0 / 8;

			Stuck_objects[i].wallnum = -1;

			Num_stuck_objects--;
		}
	}

	Assert(Num_stuck_objects == 0);

}

// -----------------------------------------------------------------------------------
#define	MAX_BLAST_GLASS_DEPTH	5

void bng_process_segment(object * objp, fix damage, segment * segp, int depth, int8_t * visited)
{
	int	i, sidenum;

	if (depth > MAX_BLAST_GLASS_DEPTH)
		return;

	depth++;

	for (sidenum = 0; sidenum < MAX_SIDES_PER_SEGMENT; sidenum++) {
		int			tm;
		fix			dist;
		vms_vector	pnt;

		//	Process only walls which have glass.
		if ((tm = segp->sides[sidenum].tmap_num2) != 0) {
			int	ec, db;

			tm &= 0x3fff;			//tm without flags

			if ((((ec = TmapInfo[tm].eclip_num) != -1) && ((db = Effects[ec].dest_bm_num) != -1 && !(Effects[ec].flags & EF_ONE_SHOT))) || (ec == -1 && (TmapInfo[tm].destroyed != -1))) {
				compute_center_point_on_side(&pnt, segp, sidenum);
				dist = vm_vec_dist_quick(&pnt, &objp->pos);
				if (dist < damage / 2) {
					dist = find_connected_distance(&pnt, segp - Segments, &objp->pos, objp->segnum, MAX_BLAST_GLASS_DEPTH, WID_RENDPAST_FLAG);
					if ((dist > 0) && (dist < damage / 2))
						check_effect_blowup(segp, sidenum, &pnt, &Objects[objp->ctype.laser_info.parent_num], 1);
				}
			}
		}
	}

	for (i = 0; i < MAX_SIDES_PER_SEGMENT; i++) {
		int	segnum = segp->children[i];

		if (segnum != -1) {
			if (!visited[segnum]) {
				if (WALL_IS_DOORWAY(segp, i) & WID_FLY_FLAG) {
					visited[segnum] = 1;
					bng_process_segment(objp, damage, &Segments[segnum], depth, visited);
				}
			}
		}
	}
}

// -----------------------------------------------------------------------------------
//	objp is going to detonate
//	blast nearby monitors, lights, maybe other things
void blast_nearby_glass(object* objp, fix damage)
{
	int		i;
	int8_t		visited[MAX_SEGMENTS];
	segment* cursegp;

	cursegp = &Segments[objp->segnum];
	for (i = 0; i <= Highest_segment_index; i++)
		visited[i] = 0;

	visited[objp->segnum] = 1;
	bng_process_segment(objp, damage, cursegp, 0, visited);
}

#include "cfile/cfile.h"

void read_wall(wall* nwall, FILE* fp)
{
	nwall->segnum = file_read_int(fp);
	nwall->sidenum = file_read_int(fp);
	nwall->hps = file_read_int(fp);
	nwall->linked_wall = file_read_int(fp);
	nwall->type = file_read_byte(fp);
	nwall->flags = file_read_byte(fp);
	nwall->state = file_read_byte(fp);
	nwall->trigger = file_read_byte(fp);
	nwall->clip_num = file_read_byte(fp);
	nwall->keys = file_read_byte(fp);
	nwall->controlling_trigger = file_read_byte(fp);
	nwall->cloak_value = file_read_byte(fp);
}

void read_active_door(active_door* door, FILE* fp)
{
	door->n_parts = file_read_int(fp);
	door->front_wallnum[0] = file_read_short(fp);
	door->front_wallnum[1] = file_read_short(fp);
	door->back_wallnum[0] = file_read_short(fp);
	door->back_wallnum[1] = file_read_short(fp);
	door->time = file_read_int(fp);
}

void P_ReadCloakingWall(cloaking_wall* wall, FILE* fp)
{
	int i;
	wall->front_wallnum = file_read_short(fp);
	wall->back_wallnum = file_read_short(fp);
	for (i = 0; i < 4; i++)
		wall->front_ls[i] = file_read_int(fp);
	for (i = 0; i < 4; i++)
		wall->back_ls[i] = file_read_int(fp);
	wall->time = file_read_int(fp);
}

void write_wall(wall* nwall, FILE* fp)
{
	file_write_int(fp, nwall->segnum);
	file_write_int(fp, nwall->sidenum);
	file_write_int(fp, nwall->hps);
	file_write_int(fp, nwall->linked_wall);
	file_write_byte(fp, nwall->type);
	file_write_byte(fp, nwall->flags);
	file_write_byte(fp, nwall->state);
	file_write_byte(fp, nwall->trigger);
	file_write_byte(fp, nwall->clip_num);
	file_write_byte(fp, nwall->keys);
	file_write_byte(fp, nwall->controlling_trigger);
	file_write_byte(fp, nwall->cloak_value);
}

void write_active_door(active_door* door, FILE* fp)
{
	file_write_int(fp, door->n_parts);
	file_write_short(fp, door->front_wallnum[0]);
	file_write_short(fp, door->front_wallnum[1]);
	file_write_short(fp, door->back_wallnum[0]);
	file_write_short(fp, door->back_wallnum[1]);
	file_write_int(fp, door->time);
}

void P_WriteCloakingWall(cloaking_wall* wall, FILE* fp)
{
	int i;
	file_write_short(fp, wall->front_wallnum);
	file_write_short(fp, wall->back_wallnum);
	for (i = 0; i < 4; i++)
		file_write_int(fp, wall->front_ls[i]);
	for (i = 0; i < 4; i++)
		file_write_int(fp, wall->back_ls[i]);
	file_write_int(fp, wall->time);
}
